const TabContext = React.createContext<{active:string;setActive:(s:string)=>void}|null>(null);

function Tabs({ children, defaultTab }: { children: React.ReactNode; defaultTab: string }) {
  const [active, setActive] = React.useState(defaultTab);
  return <TabContext.Provider value={{active,setActive}}>{children}</TabContext.Provider>;
}

function Tab({ id, children }: { id: string; children: React.ReactNode }) {
  const ctx = React.useContext(TabContext)!;
  return <button onClick={()=>ctx.setActive(id)} className={ctx.active===id?'active':''}>{children}</button>;
}

function Panel({ id, children }: { id: string; children: React.ReactNode }) {
  const ctx = React.useContext(TabContext)!;
  return ctx.active===id ? <div>{children}</div> : null;
}

function useLocalStorage<T>(key: string, initial: T) {
  const [value, setValue] = React.useState<T>(() => {
    try { return JSON.parse(localStorage.getItem(key)!) ?? initial; } catch { return initial; }
  });
  React.useEffect(() => { localStorage.setItem(key, JSON.stringify(value)); }, [key, value]);
  return [value, setValue] as const;
}

function useDebounce<T>(value: T, delay = 300) {
  const [debounced, setDebounced] = React.useState(value);
  React.useEffect(() => { const t = setTimeout(() => setDebounced(value), delay); return () => clearTimeout(t); }, [value, delay]);
  return debounced;
}

function useMediaQuery(query: string) {
  const [matches, setMatches] = React.useState(false);
  React.useEffect(() => {
    const mql = window.matchMedia(query);
    setMatches(mql.matches);
    const handler = (e: MediaQueryListEvent) => setMatches(e.matches);
    mql.addEventListener('change', handler);
    return () => mql.removeEventListener('change', handler);
  }, [query]);
  return matches;
}

class ErrorBoundary extends React.Component<
  { children: React.ReactNode; fallback?: React.ReactNode },
  { hasError: boolean; error: Error | null }
> {
  state = { hasError: false, error: null as Error | null };
  static getDerivedStateFromError(error: Error) { return { hasError: true, error }; }
  componentDidCatch(error: Error, info: React.ErrorInfo) { console.error('Boundary caught:', error, info); }
  render() {
    if (this.state.hasError) {
      return this.props.fallback ?? (
        <div className="p-8 text-center">
          <h2 className="text-xl font-bold text-red-500">Something went wrong</h2>
          <p className="text-gray-500 mt-2">{this.state.error?.message}</p>
          <button onClick={() => this.setState({ hasError: false })} className="mt-4 px-4 py-2 bg-blue-500 text-white rounded">Try Again</button>
        </div>
      );
    }
    return this.props.children;
  }
}

function Toggle({ children }: { children: (props: { on: boolean; toggle: () => void }) => React.ReactNode }) {
  const [on, setOn] = React.useState(false);
  return <>{children({ on, toggle: () => setOn(prev => !prev) })}</>;
}

