type State = { items: string[]; loading: boolean };
type Action = { type: 'ADD'; item: string } | { type: 'REMOVE'; index: number } | { type: 'SET_LOADING'; loading: boolean };

function reducer(state: State, action: Action): State {
  switch (action.type) {
    case 'ADD': return { ...state, items: [...state.items, action.item] };
    case 'REMOVE': return { ...state, items: state.items.filter((_, i) => i !== action.index) };
    case 'SET_LOADING': return { ...state, loading: action.loading };
  }
}

const StateCtx = React.createContext<State>({ items: [], loading: false });
const DispatchCtx = React.createContext<React.Dispatch<Action>>(() => {});

function Provider({ children }: { children: React.ReactNode }) {
  const [state, dispatch] = React.useReducer(reducer, { items: [], loading: false });
  return <StateCtx.Provider value={state}><DispatchCtx.Provider value={dispatch}>{children}</DispatchCtx.Provider></StateCtx.Provider>;
}

const useAppState = () => React.useContext(StateCtx);
const useAppDispatch = () => React.useContext(DispatchCtx);

